      <h1 class="text-2xl font-black text-slate-900 dark:text-slate-100 tracking-tight uppercase leading-none">Monitoreo del Sistema</h1>
      <p class="text-slate-500 dark:text-slate-400 text-xs mt-2">Estado general de la base de datos, memoria del servidor, procesador y copias de seguridad.</p>
    </div>
    <button 
      (click)="loadStatus()" 
      class="w-full sm:w-auto px-4 py-2 border border-slate-300 dark:border-slate-700 bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700 text-slate-800 dark:text-slate-100 text-[10px] font-bold uppercase tracking-widest transition-colors flex items-center justify-center gap-2 rounded-none">
      <span class="material-symbols-outlined text-sm">refresh</span>
      <span>Actualizar Estado</span>
    </button>
  </div>

  <!-- Loading State -->
