    <span class="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">Consultando métricas de salud...</span>
  </div>

  <!-- Error message -->
  <div *ngIf="errorMsg" class="flex items-start gap-3 bg-red-50 dark:bg-red-950/30 border border-red-200 dark:border-red-900/40 text-red-800 dark:text-red-200 p-4 rounded-none text-xs font-semibold">
    <span class="material-symbols-outlined text-red-600 text-base">warning</span>
    <div class="flex-grow">
      <span class="block font-bold">Error de Monitoreo</span>
      <span class="block font-normal mt-0.5">{{ errorMsg }}</span>
    </div>
  </div>

  <!-- Success message for Backup -->
  <div *ngIf="backupSuccessMsg" class="flex items-start gap-3 bg-emerald-50 dark:bg-emerald-950/30 border border-emerald-200 dark:border-emerald-900/40 text-emerald-800 dark:text-emerald-200 p-4 rounded-none text-xs font-semibold">
    <span class="material-symbols-outlined text-emerald-600 text-base">check_circle</span>
    <div class="flex-grow">
      <span class="block font-bold">Copia de Seguridad Completada</span>
      <span class="block font-normal mt-0.5">{{ backupSuccessMsg }}</span>
    </div>
  </div>

  <!-- Main System Info Cards -->
  <div *ngIf="!isLoading && statusData" class="space-y-6">

    <!-- Row 1: Vital Stats Grid — 1 col mobile, 2 col sm, 4 col md -->
    <div class="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-4 gap-6">

      <!-- Backend health -->
      <div class="border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 p-6 shadow-[4px_4px_0px_0px_rgba(15,23,42,0.02)] dark:shadow-[4px_4px_0px_0px_rgba(0,0,0,0.22)] flex flex-col justify-between transition-colors duration-300">
        <div>
          <span class="text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest block">Servidor Backend</span>
          <h3 class="text-lg font-black text-slate-900 dark:text-slate-100 uppercase mt-1">Servicio Web</h3>
        </div>
        <div class="mt-6 flex items-center gap-2">
          <span class="relative flex h-2.5 w-2.5">
            <span class="animate-ping absolute inline-flex h-full w-full rounded-full bg-emerald-400 opacity-75"></span>
            <span class="relative inline-flex rounded-full h-2.5 w-2.5 bg-emerald-500"></span>
          </span>
          <span class="text-xs font-black uppercase text-emerald-700 tracking-wider">
            {{ statusData.backendStatus }}
          </span>
        </div>
      </div>

      <!-- Database health -->
      <div class="border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 p-6 shadow-[4px_4px_0px_0px_rgba(15,23,42,0.02)] dark:shadow-[4px_4px_0px_0px_rgba(0,0,0,0.22)] flex flex-col justify-between transition-colors duration-300">
        <div>
          <span class="text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest block">Base de Datos</span>
          <h3 class="text-lg font-black text-slate-900 dark:text-slate-100 uppercase mt-1">PostgreSQL</h3>
        </div>
        <div class="mt-6">
          <span [ngClass]="statusData.databaseStatus === 'CONECTADO' ? 'text-emerald-700' : 'text-red-700'" class="text-xs font-black uppercase tracking-wider">
            {{ statusData.databaseStatus }}
          </span>
        </div>
      </div>

      <!-- CPU load -->
      <div class="border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 p-6 shadow-[4px_4px_0px_0px_rgba(15,23,42,0.02)] dark:shadow-[4px_4px_0px_0px_rgba(0,0,0,0.22)] flex flex-col justify-between transition-colors duration-300">
        <div>
          <span class="text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest block">Carga de Procesador</span>
          <h3 class="text-lg font-black text-slate-900 dark:text-slate-100 uppercase mt-1">Uso de CPU</h3>
        </div>
        <div class="mt-6">
          <span class="text-base font-black text-slate-900 font-mono">
            {{ statusData.cpuLoad }}
          </span>
        </div>
      </div>

      <!-- Backups control -->
      <div class="border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 p-6 shadow-[4px_4px_0px_0px_rgba(15,23,42,0.02)] dark:shadow-[4px_4px_0px_0px_rgba(0,0,0,0.22)] flex flex-col justify-between transition-colors duration-300">
        <div>
          <span class="text-[9px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest block">Copia de Seguridad</span>
          <h3 class="text-xs font-bold text-slate-900 dark:text-slate-100 uppercase mt-1 leading-tight">Último: <span class="font-mono block text-[10px] text-slate-500 dark:text-slate-400 mt-0.5">{{ statusData.ultimoBackup }}</span></h3>
        </div>
        <div class="mt-4">
          <button 
            (click)="triggerBackup()"
            [disabled]="isBackupLoading"
            class="w-full flex items-center justify-center gap-1.5 py-2 bg-slate-900 dark:bg-slate-100 hover:bg-slate-800 dark:hover:bg-slate-200 text-white dark:text-slate-900 font-bold text-[9px] uppercase tracking-widest transition-colors rounded-none disabled:opacity-50">
            <span class="material-symbols-outlined text-xs">backup</span>
            <span>{{ isBackupLoading ? 'Generando...' : 'Backup Ahora' }}</span>
          </button>
        </div>
      </div>

    </div>

    <!-- Row 2: Resources Gauges — 1 col mobile, 2 col md -->
    <div class="grid grid-cols-1 md:grid-cols-2 gap-6">

      <!-- Disk Usage details -->
      <div class="border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 p-6 shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] dark:shadow-[4px_4px_0px_0px_rgba(0,0,0,0.22)] rounded-none transition-colors duration-300">
        <h3 class="text-xs font-black text-slate-900 dark:text-slate-100 uppercase tracking-widest mb-6">Uso de Disco (Servidor)</h3>

        <div class="space-y-4">
          <div class="w-full bg-slate-100 dark:bg-slate-800 h-3 rounded-none overflow-hidden border border-slate-200 dark:border-slate-700">
            <div 
              [style.width.%]="statusData.discoPorcentajeUsado"
              class="bg-slate-950 h-full transition-all duration-500">
            </div>
          </div>

          <div class="grid grid-cols-3 text-center divide-x divide-slate-200 dark:divide-slate-800 pt-2">
            <div>
              <span class="block text-[8px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider">Total</span>
              <span class="text-xs font-black text-slate-800 dark:text-slate-200 font-mono">{{ statusData.discoTotalGb }}</span>
            </div>
            <div>
              <span class="block text-[8px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider">Usado</span>
              <span class="text-xs font-black text-slate-800 dark:text-slate-200 font-mono">{{ statusData.discoUsadoGb }} ({{ statusData.discoPorcentajeUsado | number:'1.0-1' }}%)</span>
            </div>
            <div>
              <span class="block text-[8px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider">Disponible</span>
              <span class="text-xs font-black text-slate-800 dark:text-slate-200 font-mono">{{ statusData.discoLibreGb }}</span>
            </div>
          </div>
        </div>
      </div>

      <!-- JVM Memory Usage details -->
      <div class="border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 p-6 shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] dark:shadow-[4px_4px_0px_0px_rgba(0,0,0,0.22)] rounded-none transition-colors duration-300">
        <h3 class="text-xs font-black text-slate-900 dark:text-slate-100 uppercase tracking-widest mb-6">Memoria de la JVM (Java)</h3>

        <div class="space-y-4">
          <div class="w-full bg-slate-100 dark:bg-slate-800 h-3 rounded-none overflow-hidden border border-slate-200 dark:border-slate-700">
            <div 
              [style.width.%]="statusData.jvmPorcentajeUsado"
              class="bg-slate-950 h-full transition-all duration-500">
            </div>
          </div>

          <!-- 2-col on mobile, 4-col on sm+ for the JVM stats -->
          <div class="grid grid-cols-2 sm:grid-cols-4 text-center divide-x divide-slate-200 dark:divide-slate-800 pt-2">
            <div>
              <span class="block text-[8px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider">Límite Max</span>
              <span class="text-xs font-black text-slate-800 dark:text-slate-200 font-mono">{{ statusData.jvmMaxMb }} MB</span>
            </div>
            <div>
              <span class="block text-[8px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider">Reservada</span>
              <span class="text-xs font-black text-slate-800 dark:text-slate-200 font-mono">{{ statusData.jvmAllocatedMb }} MB</span>
            </div>
            <div>
              <span class="block text-[8px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider">En Uso</span>
              <span class="text-xs font-black text-slate-800 dark:text-slate-200 font-mono">{{ statusData.jvmUsedMb }} MB ({{ statusData.jvmPorcentajeUsado | number:'1.0-1' }}%)</span>
            </div>
            <div>
              <span class="block text-[8px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider">Libre</span>
              <span class="text-xs font-black text-slate-800 dark:text-slate-200 font-mono">{{ statusData.jvmFreeMb }} MB</span>
            </div>
          </div>
        </div>
      </div>

    </div>
  </div>

  <!-- Confirm modal -->
  <app-confirm-modal
    [visible]="showConfirmModal"
    [type]="confirmModalType"
    [title]="confirmModalTitle"
    [message]="confirmModalMessage"
    confirmText="Confirmar"
    (onConfirm)="confirmAction()"
    (onCancel)="showConfirmModal = false">
  </app-confirm-modal>

</div>
